  if (cycle) {
    throw new SchedulerError(`Cycle detected: ${cycle.join(' -> ')}`);
  }

  const entries: ScheduleEntry[] = [];
  const scheduled = new Set<string>();
  let currentTime = 0;
  const running: Map<string, number> = new Map(); // taskId -> endTime
  const skippedRounds = new Map<string, number>();

  while (scheduled.size < tasks.size) {
    // Remove completed tasks
    for (const [taskId, endTime] of running.entries()) {
      if (endTime <= currentTime) {
        running.delete(taskId);
      }
    }

    // Find ready tasks by checking if all dependencies are scheduled, then apply anti-starvation boost based on how many rounds a task has been skipped. If no tasks are ready and there are still unscheduled tasks, jump time forward to when the next task completes.

    const ready: string[] = [];
    tasks.forEach((task, id) => {
      if (scheduled.has(id)) return;
      const depsReady = task.dependencies.every((dep) => scheduled.has(dep));
      if (depsReady) {
        ready.push(id);
      }
    });

